INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(6, 'What is a mobile device management (MDM) solution?', 'An app for managing mobile data usage', 'Software that allows organizations to remotely manage and secure mobile devices', 'A tool for speeding up mobile internet', 'A mobile antivirus application', 'Software that allows organizations to remotely manage and secure mobile devices', 'MDM solutions allow IT administrators to enforce security policies, remotely wipe lost or stolen devices, manage app installations, and monitor compliance across all mobile devices in an organization. Examples include Microsoft Intune, VMware Workspace ONE, and Jamf.'),
(6, 'What is a rogue app?', 'An app that uses too much battery', 'A malicious application disguised as a legitimate one', 'An app that is no longer supported by its developer', 'An app that requires root access', 'A malicious application disguised as a legitimate one', 'Rogue apps mimic legitimate applications to trick users into installing them. Once installed, they can steal credentials, access contacts, send premium SMS messages, or act as spyware. Always download apps from official stores and check permissions and reviews before installing.'),
(6, 'What does rooting or jailbreaking a mobile device do?', 'Improves battery performance', 'Removes manufacturer restrictions giving full OS access but reducing security', 'Encrypts the device storage', 'Resets the device to factory settings', 'Removes manufacturer restrictions giving full OS access but reducing security', 'Rooting (Android) or jailbreaking (iOS) removes the built-in security restrictions of the operating system. While it allows more customization, it also disables security features like Secure Boot, exposes the device to malware, and voids warranties. Enterprise MDM policies typically block rooted devices.'),
(6, 'What is SMS phishing also known as?', 'Vishing', 'Smishing', 'Spishing', 'Pharming', 'Smishing', 'Smishing (SMS phishing) uses text messages to trick victims into clicking malicious links or calling fraudulent numbers. Messages often impersonate banks, delivery services, or government agencies. Never click links in unexpected SMS messages and verify directly with the organization.'),
(6, 'What is the risk of using public USB charging stations?', 'They charge devices too slowly', 'They can be used to install malware or steal data via juice jacking', 'They can damage the battery', 'They only work with certain phone brands', 'They can be used to install malware or steal data via juice jacking', 'Juice jacking is an attack where malicious hardware or software is installed in public USB charging ports. When you plug in your device, attackers can install malware or steal data. Use AC power outlets or carry your own power bank to avoid this risk.'),
(6, 'What is mobile application sandboxing?', 'Testing apps in a development environment', 'Isolating apps from each other and the OS to limit damage if compromised', 'Compressing app data to save storage', 'Blocking apps from accessing the internet', 'Isolating apps from each other and the OS to limit damage if compromised', 'Mobile OS sandboxing restricts each app to its own isolated environment, preventing it from accessing data belonging to other apps or making unauthorized system calls. This limits the damage a malicious or compromised app can cause. Both Android and iOS implement sandboxing as a core security feature.'),
(6, 'What is the purpose of mobile device encryption?', 'To speed up the device processor', 'To protect data stored on the device if it is lost or stolen', 'To compress files and save storage space', 'To prevent apps from using too much memory', 'To protect data stored on the device if it is lost or stolen', 'Full-device encryption converts all data on the device into an unreadable format that can only be decrypted with the correct PIN, password, or biometric. If the device is lost or stolen, the data remains protected. Modern iOS and Android devices enable encryption by default.'),
(6, 'What is a mobile VPN used for?', 'To increase mobile data speed', 'To encrypt internet traffic from a mobile device on untrusted networks', 'To block ads on mobile browsers', 'To extend battery life', 'To encrypt internet traffic from a mobile device on untrusted networks', 'A mobile VPN encrypts all internet traffic from your smartphone or tablet, protecting it from eavesdropping on public Wi-Fi networks. It also masks your IP address and location. This is especially important when accessing corporate resources or sensitive accounts on the go.'),
(6, 'What should you check before granting app permissions?', 'The app download size', 'Whether the requested permissions are necessary for the app functionality', 'The app developer country of origin', 'The number of app updates released', 'Whether the requested permissions are necessary for the app functionality', 'Apps often request more permissions than they need. A flashlight app requesting access to your contacts or microphone is a red flag. Always review permissions before installing and revoke unnecessary ones in your device settings. Both Android and iOS allow per-permission control.'),
(6, 'What is mobile threat defense (MTD)?', 'A firewall built into mobile chipsets', 'Security software that detects and responds to threats on mobile devices', 'A government program for mobile security standards', 'An encryption standard for mobile communications', 'Security software that detects and responds to threats on mobile devices', 'MTD solutions monitor mobile devices for threats including malicious apps, network attacks, OS vulnerabilities, and phishing attempts. They integrate with MDM platforms to enforce compliance policies and can automatically quarantine compromised devices. Examples include Lookout, Zimperium, and Microsoft Defender for Endpoint.');
INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(7, 'What is static malware analysis?', 'Running malware in a controlled environment to observe behavior', 'Examining malware code and properties without executing it', 'Analyzing malware network traffic', 'Comparing malware to known virus signatures only', 'Examining malware code and properties without executing it', 'Static analysis examines malware without running it. Analysts inspect the binary, strings, imports, headers, and disassembled code to understand its capabilities. Tools include IDA Pro, Ghidra, and strings utilities. It is safe since the malware is never executed, but obfuscated malware can be harder to analyze statically.'),
(7, 'What is dynamic malware analysis?', 'Analyzing malware source code in a text editor', 'Executing malware in a controlled sandbox to observe its behavior', 'Comparing malware hash values against a database', 'Scanning malware with multiple antivirus engines', 'Executing malware in a controlled sandbox to observe its behavior', 'Dynamic analysis runs malware in an isolated sandbox environment and monitors its behavior including file system changes, registry modifications, network connections, and process creation. Tools include Cuckoo Sandbox, Any.run, and Joe Sandbox. It reveals actual behavior but risks escape from the sandbox.'),
(7, 'What is a trojan horse in cybersecurity?', 'A virus that spreads through email attachments only', 'Malware disguised as legitimate software that performs hidden malicious actions', 'A type of ransomware that targets financial institutions', 'A network worm that replicates across systems', 'Malware disguised as legitimate software that performs hidden malicious actions', 'A Trojan horse appears to be useful software but contains hidden malicious functionality. Unlike viruses, Trojans do not self-replicate. They are commonly used to create backdoors, steal credentials, download additional malware, or give attackers remote access. They rely on social engineering to trick users into installing them.'),
(7, 'What is a rootkit?', 'A tool for managing system root accounts', 'Malware designed to hide its presence and maintain privileged access on a system', 'A type of keylogger that records root user activity', 'A legitimate system administration toolkit', 'Malware designed to hide its presence and maintain privileged access on a system', 'Rootkits operate at a deep level of the OS, often modifying the kernel, to hide malicious processes, files, and network connections from security tools. They are extremely difficult to detect and remove. Kernel-level rootkits may require a complete OS reinstall. Secure Boot and integrity checking help prevent rootkit installation.'),
(7, 'What is a worm in the context of malware?', 'A virus that only infects document files', 'Self-replicating malware that spreads across networks without user interaction', 'Malware that encrypts files and demands ransom', 'A type of adware that displays pop-up advertisements', 'Self-replicating malware that spreads across networks without user interaction', 'Unlike viruses that require a host file, worms are standalone programs that self-replicate and spread automatically across networks by exploiting vulnerabilities. Famous examples include WannaCry, Conficker, and Morris Worm. They can cause massive damage by consuming bandwidth and installing additional payloads.'),
(7, 'What is a keylogger?', 'A tool that logs all keyboard shortcuts used in an OS', 'Malware that records keystrokes to capture passwords and sensitive data', 'A hardware device for testing keyboard input', 'A legitimate accessibility tool for tracking typing speed', 'Malware that records keystrokes to capture passwords and sensitive data', 'Keyloggers capture every keystroke made on a device, including passwords, credit card numbers, and private messages. They can be software-based (running as a background process) or hardware-based (physical devices plugged between keyboard and computer). Detection requires behavioral monitoring and endpoint security tools.'),
(7, 'What is a fileless malware attack?', 'Malware stored in hidden files on the hard drive', 'Malware that operates entirely in memory without writing files to disk', 'An attack that deletes all files on a system', 'Malware that only targets file servers', 'Malware that operates entirely in memory without writing files to disk', 'Fileless malware lives entirely in RAM and uses legitimate system tools like PowerShell, WMI, or the Windows Registry to execute malicious code. Because nothing is written to disk, traditional file-based antivirus solutions often miss it. Detection requires behavioral analysis and memory scanning.'),
(7, 'What is a Command and Control (C2) server?', 'A server used to manage legitimate software deployments', 'A remote server used by attackers to send commands to compromised systems', 'A backup server for critical business data', 'A server that controls network traffic routing', 'A remote server used by attackers to send commands to compromised systems', 'C2 servers are the infrastructure attackers use to communicate with malware on compromised systems. They send commands, receive stolen data, and deliver additional payloads. Blocking known C2 domains and IP addresses, and monitoring for unusual outbound connections, are key defenses.'),
(7, 'What is the purpose of malware obfuscation?', 'To make malware run faster on infected systems', 'To disguise malware code to evade detection by security tools', 'To compress malware files for easier distribution', 'To encrypt malware communications', 'To disguise malware code to evade detection by security tools', 'Malware authors use obfuscation techniques like code packing, encryption, polymorphism, and metamorphism to make their malware harder to detect and analyze. Polymorphic malware changes its code signature with each infection while maintaining the same functionality, defeating signature-based detection.'),
(7, 'What is a dropper in malware terminology?', 'Malware that causes systems to crash', 'A type of malware that installs other malicious software onto a system', 'A tool used to remove malware from infected systems', 'Malware that drops fake security alerts', 'A type of malware that installs other malicious software onto a system', 'A dropper is a carrier malware whose primary purpose is to deliver and install other malware payloads onto a target system. The dropper itself may be benign-looking and may delete itself after installing the payload to avoid detection. Droppers are commonly distributed via phishing emails and malicious downloads.');
INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(8, 'What is a hash function in cryptography?', 'A function that encrypts data with a key', 'A one-way function that converts data into a fixed-size digest', 'A method for generating random encryption keys', 'A technique for compressing large files', 'A one-way function that converts data into a fixed-size digest', 'A cryptographic hash function takes input data of any size and produces a fixed-size output (digest). It is one-way meaning you cannot reverse it to get the original data. The same input always produces the same output, and even a tiny change in input produces a completely different hash. Common algorithms include SHA-256 and SHA-3.'),
(8, 'What is a digital signature?', 'An electronic version of a handwritten signature image', 'A cryptographic mechanism to verify the authenticity and integrity of a message', 'A certificate issued by a certificate authority', 'A method for encrypting email attachments', 'A cryptographic mechanism to verify the authenticity and integrity of a message', 'A digital signature uses asymmetric cryptography where the sender signs data with their private key. Recipients verify the signature using the sender public key. This proves the message came from the claimed sender and has not been altered. Digital signatures are used in code signing, email (S/MIME), and document signing.'),
(8, 'What is a Public Key Infrastructure (PKI)?', 'A network of public Wi-Fi access points', 'A framework for managing digital certificates and public-key encryption', 'A type of symmetric encryption system', 'A government database of public encryption keys', 'A framework for managing digital certificates and public-key encryption', 'PKI is a system of hardware, software, policies, and procedures for creating, managing, distributing, and revoking digital certificates. It enables secure communications by binding public keys to identities through Certificate Authorities (CAs). PKI underpins HTTPS, email encryption, VPNs, and code signing.'),
(8, 'What is the difference between a block cipher and a stream cipher?', 'Block ciphers are faster; stream ciphers are more secure', 'Block ciphers encrypt fixed-size chunks of data; stream ciphers encrypt one bit or byte at a time', 'Block ciphers use symmetric keys; stream ciphers use asymmetric keys', 'There is no practical difference between them', 'Block ciphers encrypt fixed-size chunks of data; stream ciphers encrypt one bit or byte at a time', 'Block ciphers like AES process data in fixed blocks (e.g., 128 bits) and are used for bulk data encryption. Stream ciphers like RC4 encrypt data one bit or byte at a time and are suited for real-time communications. AES in CTR mode effectively turns a block cipher into a stream cipher.'),
(8, 'What is a rainbow table attack?', 'An attack using colorful social engineering techniques', 'Using precomputed hash values to crack password hashes quickly', 'A multi-vector attack combining several techniques', 'An attack targeting network routing protocols', 'Using precomputed hash values to crack password hashes quickly', 'Rainbow tables are precomputed tables of hash values for common passwords. Attackers compare stolen password hashes against the table to find matches. The defense is salting: adding a unique random value to each password before hashing, making precomputed tables useless since each salt creates a unique hash.'),
(8, 'What is perfect forward secrecy (PFS)?', 'A guarantee that encrypted data will never be decrypted', 'A property ensuring session keys cannot be compromised even if the long-term key is stolen', 'A method for storing encryption keys securely', 'An algorithm that generates perfect random numbers', 'A property ensuring session keys cannot be compromised even if the long-term key is stolen', 'PFS ensures that each session uses a unique ephemeral key derived through key exchange protocols like Diffie-Hellman. Even if an attacker later obtains the server private key, they cannot decrypt past sessions because the session keys were never stored. TLS 1.3 mandates PFS for all connections.'),
(8, 'What is homomorphic encryption?', 'Encryption that looks the same from both ends', 'Encryption that allows computations on encrypted data without decrypting it', 'A symmetric encryption algorithm used in databases', 'Encryption that uses the same key for multiple users', 'Encryption that allows computations on encrypted data without decrypting it', 'Homomorphic encryption allows mathematical operations to be performed on ciphertext, producing an encrypted result that when decrypted matches the result of operations on the plaintext. This enables cloud services to process sensitive data without ever seeing it in plaintext, with applications in healthcare and finance.'),
(8, 'What is a certificate revocation list (CRL)?', 'A list of expired SSL certificates', 'A list of digital certificates that have been revoked before their expiration date', 'A list of trusted certificate authorities', 'A log of all issued certificates in a PKI system', 'A list of digital certificates that have been revoked before their expiration date', 'A CRL is published by a Certificate Authority and lists certificates that have been revoked due to compromise, key loss, or policy violations. Browsers and applications check CRLs to ensure a certificate is still valid. OCSP (Online Certificate Status Protocol) is a faster alternative that checks individual certificate status in real time.'),
(8, 'What is the Diffie-Hellman key exchange?', 'A method for sharing passwords securely over email', 'A protocol allowing two parties to establish a shared secret over an insecure channel', 'An asymmetric encryption algorithm for securing data', 'A digital signature scheme used in TLS', 'A protocol allowing two parties to establish a shared secret over an insecure channel', 'Diffie-Hellman allows two parties to independently compute a shared secret using public information and their own private values, without ever transmitting the secret itself. Even if an attacker intercepts all communications, they cannot compute the shared secret without solving the discrete logarithm problem. It is the basis for key exchange in TLS and SSH.'),
(8, 'What is quantum cryptography?', 'Cryptography performed by quantum computers to break encryption', 'Using quantum mechanical properties to create theoretically unbreakable encryption', 'A faster version of RSA encryption', 'Encryption designed to run on quantum processors only', 'Using quantum mechanical properties to create theoretically unbreakable encryption', 'Quantum cryptography, particularly Quantum Key Distribution (QKD), uses quantum mechanical principles like the Heisenberg uncertainty principle to distribute encryption keys. Any eavesdropping attempt disturbs the quantum states and is detectable. Post-quantum cryptography refers to classical algorithms resistant to quantum computer attacks.');
INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(9, 'What is reconnaissance in penetration testing?', 'Writing the final penetration test report', 'Gathering information about a target before launching an attack', 'Exploiting vulnerabilities in a target system', 'Cleaning up traces after a penetration test', 'Gathering information about a target before launching an attack', 'Reconnaissance (recon) is the first phase of penetration testing where testers gather as much information as possible about the target. Passive recon uses public sources like OSINT, WHOIS, and social media. Active recon involves direct interaction with the target such as port scanning. This phase informs the attack strategy.'),
(9, 'What is the difference between a white-box and black-box penetration test?', 'White-box tests web apps; black-box tests networks', 'White-box testers have full system knowledge; black-box testers have no prior knowledge', 'White-box is automated; black-box is manual', 'White-box tests during the day; black-box tests at night', 'White-box testers have full system knowledge; black-box testers have no prior knowledge', 'In a white-box test, testers are given full knowledge of the target including source code, architecture, and credentials, simulating an insider threat. Black-box testing simulates an external attacker with no prior knowledge. Gray-box testing falls in between. Each approach tests different aspects of security posture.'),
(9, 'What is Metasploit?', 'A network monitoring tool', 'A penetration testing framework for developing and executing exploits', 'An intrusion detection system', 'A vulnerability scanner for web applications', 'A penetration testing framework for developing and executing exploits', 'Metasploit is an open-source penetration testing framework that provides tools for discovering vulnerabilities, developing exploits, and executing them against target systems. It includes a large database of known exploits, payloads, and auxiliary modules. It is widely used by security professionals for authorized penetration testing.'),
(9, 'What is privilege escalation in hacking?', 'Creating new administrator accounts on a system', 'Gaining higher access rights than originally granted on a compromised system', 'Escalating a security incident to management', 'Increasing the processing priority of a malicious process', 'Gaining higher access rights than originally granted on a compromised system', 'After gaining initial access to a system, attackers often have limited privileges. Privilege escalation exploits vulnerabilities or misconfigurations to gain higher privileges such as administrator or root access. Vertical escalation gains higher privileges; horizontal escalation accesses other accounts at the same privilege level.'),
(9, 'What is a CVE (Common Vulnerabilities and Exposures)?', 'A certification for cybersecurity professionals', 'A standardized identifier for publicly known cybersecurity vulnerabilities', 'A type of malware classification system', 'A compliance framework for vulnerability management', 'A standardized identifier for publicly known cybersecurity vulnerabilities', 'CVE is a publicly available dictionary of known cybersecurity vulnerabilities maintained by MITRE. Each CVE entry has a unique identifier (e.g., CVE-2021-44228 for Log4Shell), a description, and references. The CVSS score rates severity. Security teams use CVEs to prioritize patching and track known vulnerabilities.'),
(9, 'What is fuzzing in security testing?', 'Making security reports unclear to hide findings', 'Sending random or malformed input to an application to find vulnerabilities', 'Testing applications with blurred or obscured data', 'A technique for obfuscating malware code', 'Sending random or malformed input to an application to find vulnerabilities', 'Fuzzing (fuzz testing) automatically generates large amounts of random, unexpected, or malformed input and feeds it to an application to trigger crashes, memory leaks, or unexpected behavior that may indicate security vulnerabilities. Modern fuzzers like AFL and libFuzzer use coverage-guided techniques to maximize code path exploration.'),
(9, 'What is lateral movement in a cyberattack?', 'Moving attack infrastructure to different servers', 'Techniques attackers use to progressively move through a network after initial compromise', 'Changing the direction of a DDoS attack', 'Moving malware files between directories', 'Techniques attackers use to progressively move through a network after initial compromise', 'After gaining initial access, attackers use lateral movement techniques to explore the network, escalate privileges, and reach high-value targets. Techniques include pass-the-hash, pass-the-ticket, remote service exploitation, and credential dumping. Network segmentation and monitoring for unusual internal traffic help detect lateral movement.'),
(9, 'What is OSINT (Open Source Intelligence)?', 'Intelligence gathered from classified government sources', 'Collecting information from publicly available sources for security research', 'Open-source security software for intelligence agencies', 'A type of network scanning technique', 'Collecting information from publicly available sources for security research', 'OSINT involves gathering and analyzing information from publicly available sources including websites, social media, public records, DNS data, job postings, and forums. Security professionals use OSINT for reconnaissance during penetration tests and threat intelligence. Tools include Maltego, Shodan, theHarvester, and Recon-ng.'),
(9, 'What is a buffer overflow vulnerability?', 'A network buffer that becomes too full during a DDoS attack', 'Writing more data to a buffer than it can hold, overwriting adjacent memory', 'A database error caused by too many simultaneous connections', 'An overflow of log files filling up disk space', 'Writing more data to a buffer than it can hold, overwriting adjacent memory', 'A buffer overflow occurs when a program writes more data to a buffer than it was allocated, overwriting adjacent memory. Attackers can exploit this to overwrite return addresses and redirect execution to malicious code. Defenses include input validation, stack canaries, ASLR (Address Space Layout Randomization), and DEP (Data Execution Prevention).'),
(9, 'What is the MITRE ATT&CK framework?', 'A certification program for ethical hackers', 'A knowledge base of adversary tactics and techniques based on real-world observations', 'A vulnerability scoring system', 'A compliance standard for penetration testing firms', 'A knowledge base of adversary tactics and techniques based on real-world observations', 'MITRE ATT&CK is a globally accessible knowledge base of adversary tactics, techniques, and procedures (TTPs) based on real-world cyberattacks. It is organized into matrices covering Enterprise, Mobile, and ICS environments. Security teams use it for threat modeling, red team planning, detection engineering, and gap analysis.');
INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(10, 'What is GDPR?', 'A US government cybersecurity framework', 'A European Union regulation on data protection and privacy', 'A global standard for network security', 'A certification for data security professionals', 'A European Union regulation on data protection and privacy', 'The General Data Protection Regulation (GDPR) is an EU law that governs how organizations collect, process, and store personal data of EU residents. Key principles include data minimization, purpose limitation, and storage limitation. Organizations must obtain explicit consent, report breaches within 72 hours, and face fines up to 4% of global annual revenue for violations.'),
(10, 'What is the principle of data minimization?', 'Storing data in the smallest file format possible', 'Only collecting personal data that is necessary for the specified purpose', 'Minimizing the number of databases in an organization', 'Reducing data backup frequency to save costs', 'Only collecting personal data that is necessary for the specified purpose', 'Data minimization is a core GDPR principle requiring organizations to collect only the personal data that is strictly necessary for the specific purpose it was collected for. Collecting excessive data increases privacy risks and regulatory exposure. Organizations should regularly audit what data they collect and delete what is no longer needed.'),
(10, 'What is the NIST Cybersecurity Framework (CSF)?', 'A US law mandating cybersecurity standards for all companies', 'A voluntary framework providing guidelines for managing cybersecurity risk', 'A certification program for cybersecurity professionals', 'A government database of known cyber threats', 'A voluntary framework providing guidelines for managing cybersecurity risk', 'The NIST CSF provides a common language and systematic methodology for managing cybersecurity risk. It is organized around five core functions: Identify, Protect, Detect, Respond, and Recover. While voluntary for most organizations, it is widely adopted across industries and referenced in many regulatory requirements.'),
(10, 'What is PCI DSS?', 'A privacy law for healthcare organizations', 'A security standard for organizations that handle payment card data', 'A government regulation for financial institutions', 'A certification for payment processing software', 'A security standard for organizations that handle payment card data', 'The Payment Card Industry Data Security Standard (PCI DSS) is a set of security requirements for organizations that store, process, or transmit credit and debit card data. Requirements include maintaining a secure network, protecting cardholder data, implementing access controls, and regular security testing. Non-compliance can result in fines and loss of card processing privileges.'),
(10, 'What is HIPAA?', 'A cybersecurity framework for government agencies', 'A US law protecting the privacy and security of healthcare information', 'An international standard for hospital network security', 'A compliance program for pharmaceutical companies', 'A US law protecting the privacy and security of healthcare information', 'The Health Insurance Portability and Accountability Act (HIPAA) establishes national standards for protecting sensitive patient health information (PHI). The Security Rule requires administrative, physical, and technical safeguards for electronic PHI. Violations can result in civil and criminal penalties. Healthcare organizations must conduct regular risk assessments.'),
(10, 'What is a data breach notification requirement?', 'A requirement to notify employees about new data policies', 'A legal obligation to inform affected individuals and authorities when personal data is compromised', 'A requirement to back up data after a security incident', 'A notification sent to customers about new privacy features', 'A legal obligation to inform affected individuals and authorities when personal data is compromised', 'Many laws including GDPR, CCPA, and HIPAA require organizations to notify affected individuals and regulatory authorities when personal data is breached. GDPR requires notification within 72 hours of discovery. Notifications must describe the nature of the breach, data affected, likely consequences, and measures taken to address it.'),
(10, 'What is the right to be forgotten under GDPR?', 'The right to have your browsing history deleted automatically', 'The right to request deletion of your personal data under certain conditions', 'The right to remain anonymous online', 'The right to opt out of all marketing communications', 'The right to request deletion of your personal data under certain conditions', 'Article 17 of GDPR grants individuals the right to request erasure of their personal data when it is no longer necessary for its original purpose, consent is withdrawn, or the data was unlawfully processed. Organizations must comply unless they have legitimate grounds to retain the data such as legal obligations.'),
(10, 'What is ISO 27001?', 'A government regulation for information security', 'An international standard for establishing an information security management system', 'A certification for individual cybersecurity professionals', 'A technical standard for network encryption protocols', 'An international standard for establishing an information security management system', 'ISO 27001 is an internationally recognized standard that specifies requirements for establishing, implementing, maintaining, and continually improving an Information Security Management System (ISMS). Certification demonstrates to customers and partners that an organization systematically manages information security risks according to best practices.'),
(10, 'What is the Computer Fraud and Abuse Act (CFAA)?', 'A US law regulating the sale of computer hardware', 'A US federal law that criminalizes unauthorized access to computer systems', 'A regulation requiring companies to report software vulnerabilities', 'A law governing the use of encryption in the United States', 'A US federal law that criminalizes unauthorized access to computer systems', 'The CFAA is the primary US federal law addressing computer crime. It prohibits unauthorized access to protected computers, trafficking in passwords, and causing damage to computer systems. It has been used to prosecute hackers, but its broad language has also been controversial in cases involving security researchers and terms of service violations.'),
(10, 'What is privacy by design?', 'Designing websites with privacy-focused color schemes', 'Integrating privacy protections into systems and processes from the beginning', 'A design framework for creating privacy policies', 'Using anonymous design templates for user interfaces', 'Integrating privacy protections into systems and processes from the beginning', 'Privacy by design is an approach where privacy is embedded into the design and architecture of systems and business practices from the outset, rather than added as an afterthought. It is a requirement under GDPR and involves principles like data minimization, purpose limitation, default privacy settings, and end-to-end security throughout the data lifecycle.');
